# Straja — PowerShell self-contained installer
# Run in PowerShell on your business laptop.
# Creates straja\ folder in your current directory.

$root = Join-Path (Get-Location) "straja"
Write-Host "==> Creating Straja app at $root"

# Create directory structure
New-Item -ItemType Directory -Force -Path (Join-Path $root "appserver") | Out-Null
New-Item -ItemType Directory -Force -Path (Join-Path $root "appserver\static") | Out-Null
New-Item -ItemType Directory -Force -Path (Join-Path $root "appserver\static\pages") | Out-Null
New-Item -ItemType Directory -Force -Path (Join-Path $root "appserver\templates") | Out-Null
New-Item -ItemType Directory -Force -Path (Join-Path $root "bin") | Out-Null
New-Item -ItemType Directory -Force -Path (Join-Path $root "default") | Out-Null
New-Item -ItemType Directory -Force -Path (Join-Path $root "default\data") | Out-Null
New-Item -ItemType Directory -Force -Path (Join-Path $root "default\data\ui") | Out-Null
New-Item -ItemType Directory -Force -Path (Join-Path $root "default\data\ui\nav") | Out-Null
New-Item -ItemType Directory -Force -Path (Join-Path $root "default\data\ui\views") | Out-Null
New-Item -ItemType Directory -Force -Path (Join-Path $root "lookups") | Out-Null
New-Item -ItemType Directory -Force -Path (Join-Path $root "metadata") | Out-Null

# Write files
# default/app.conf
[System.IO.File]::WriteAllBytes((Join-Path $root "default\app.conf"), [Convert]::FromBase64String(""))

# default/collections.conf
[System.IO.File]::WriteAllBytes((Join-Path $root "default\collections.conf"), [Convert]::FromBase64String(""))

# default/inputs.conf
[System.IO.File]::WriteAllBytes((Join-Path $root "default\inputs.conf"), [Convert]::FromBase64String(""))

# default/props.conf
[System.IO.File]::WriteAllBytes((Join-Path $root "default\props.conf"), [Convert]::FromBase64String(""))

# default/transforms.conf
[System.IO.File]::WriteAllBytes((Join-Path $root "default\transforms.conf"), [Convert]::FromBase64String(""))

# default/savedsearches.conf
[System.IO.File]::WriteAllBytes((Join-Path $root "default\savedsearches.conf"), [Convert]::FromBase64String(""))

# default/data/ui/nav/default.xml
[System.IO.File]::WriteAllBytes((Join-Path $root "default\data\ui\nav\default.xml"), [Convert]::FromBase64String("PG5hdiBzZWFyY2hfdmlldz0ic2VhcmNoIiBjb2xvcj0iIzFlMWUyZSI+CiAgPHZpZXcgbmFtZT0ibW9uaXRvciIgZGVmYXVsdD0idHJ1ZSIgbGFiZWw9Ik1vbml0b3IiLz4KICA8dmlldyBuYW1lPSJzZWFyY2giIGxhYmVsPSJTZWFyY2giLz4KPC9uYXY+Cg=="))

# default/data/ui/views/monitor.xml
[System.IO.File]::WriteAllBytes((Join-Path $root "default\data\ui\views\monitor.xml"), [Convert]::FromBase64String("PD94bWwgdmVyc2lvbj0iMS4wIj8+Cjx2aWV3IHRlbXBsYXRlPSJiYXRjaF9tb25pdG9yOi90ZW1wbGF0ZXMvbW9uaXRvci5odG1sIiB0eXBlPSJodG1sIiBpc0Rhc2hib2FyZD0iRmFsc2UiPgogICAgPGxhYmVsPkJhdGNoIE1vbml0b3I8L2xhYmVsPgo8L3ZpZXc+Cg=="))

# metadata/default.meta
[System.IO.File]::WriteAllBytes((Join-Path $root "metadata\default.meta"), [Convert]::FromBase64String(""))

# lookups/bm_tree.csv
[System.IO.File]::WriteAllBytes((Join-Path $root "lookups\bm_tree.csv"), [Convert]::FromBase64String(""))

# bin/bm_init.py
[System.IO.File]::WriteAllBytes((Join-Path $root "bin\bm_init.py"), [Convert]::FromBase64String(""))

# bin/bm_collector.py
[System.IO.File]::WriteAllBytes((Join-Path $root "bin\bm_collector.py"), [Convert]::FromBase64String(""))

# bin/bm_setup.py
[System.IO.File]::WriteAllBytes((Join-Path $root "bin\bm_setup.py"), [Convert]::FromBase64String(""))

# appserver/static/monitor.html
[System.IO.File]::WriteAllBytes((Join-Path $root "appserver\static\monitor.html"), [Convert]::FromBase64String(""))

# appserver/templates/monitor.html
[System.IO.File]::WriteAllBytes((Join-Path $root "appserver\templates\monitor.html"), [Convert]::FromBase64String(""))

# appserver/static/pages/monitor.js
[System.IO.File]::WriteAllBytes((Join-Path $root "appserver\static\pages\monitor.js"), [Convert]::FromBase64String(""))

# appserver/static/pages/monitor.js.LICENSE.txt
[System.IO.File]::WriteAllBytes((Join-Path $root "appserver\static\pages\monitor.js.LICENSE.txt"), [Convert]::FromBase64String(""))

Write-Host ""
Write-Host "==> Done. Straja app created at: $root"
Write-Host ""
Write-Host "Transfer the straja\ folder to the Splunk server apps directory:"
Write-Host "  /opt/splunk/etc/apps/"
Write-Host ""
Write-Host "Then on the server:"
Write-Host "  /opt/splunk/bin/splunk restart"
Write-Host "  /opt/splunk/bin/splunk cmd python /opt/splunk/etc/apps/straja/bin/bm_setup.py --user admin"